let filter=document.getElementById("package_filter");if(filter){const packs=document.querySelectorAll("div.pack");filter.addEventListener("input",(function(){const filterText=this.value.toLowerCase();packs.forEach((pack=>{const name=pack.dataset.name.toLowerCase();if(name.includes(filterText)){pack.classList.remove("d-none")}else{pack.classList.add("d-none")}}))}));document.getElementById("reset_filter").addEventListener("click",(fn=>{filter.value=null;packs.forEach((pack=>{pack.classList.remove("d-none")}))}))}